+// DELETE /api/shopping-list/items
+// Clear every checked item on the active list in one atomic statement.
+// Returns 200 { removed: string[] } (the deleted item ids — an empty array
+// when nothing was checked); 404 when the household has no active list.
+export async function DELETE() {
+  const householdId = await requireHousehold()
+  if (!householdId) return unauthorized()
+
+  const list = await getActiveList(householdId)
+  if (!list) return NextResponse.json({ error: 'No active list' }, { status: 404 })
+
+  const removed = await clearCheckedItems(householdId, list.id)
+  return NextResponse.json({ removed })
+}
