+// DELETE /api/shopping-list/items — bulk-remove every checked item on the
+// active list in one statement (a single DELETE ... WHERE is atomic in
+// Postgres — no read-then-delete race window). Scoped by household_id +
+// list_id, same as every other item mutation. Returns the removed ids so the
+// client can reconcile local state without a full refetch.
+export async function clearCheckedItems(householdId: string, listId: string): Promise<string[]> {
+  const rows = await db
+    .delete(shoppingListItems)
+    .where(
+      and(
+        eq(shoppingListItems.householdId, householdId),
+        eq(shoppingListItems.listId, listId),
+        eq(shoppingListItems.checked, true),
+      ),
+    )
+    .returning({ id: shoppingListItems.id })
+  return rows.map((r) => r.id)
+}
